import { useState, useEffect } from "react";
import { getStockBySymbol } from "../services/stockService";
import StockCard from "../components/StockCard";
import { Link } from "react-router-dom";

export default function Watchlist() {
  const [watchlist, setWatchlist] = useState([]);
  const [stocks, setStocks] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const savedWatchlist = localStorage.getItem("watchlist");
    if (savedWatchlist) {
      const symbols = JSON.parse(savedWatchlist);
      setWatchlist(symbols);
      fetchWatchlistStocks(symbols);
    } else {
      setLoading(false);
    }
  }, []);

  const fetchWatchlistStocks = async (symbols) => {
    if (symbols.length === 0) {
      setStocks([]);
      setLoading(false);
      return;
    }

    try {
      const stockPromises = symbols.map(symbol => getStockBySymbol(symbol));
      const stockData = await Promise.all(stockPromises);
      setStocks(stockData);
    } catch (error) {
      console.error("Error fetching watchlist stocks:", error);
    } finally {
      setLoading(false);
    }
  };

  const toggleWatchlist = (stock) => {
    const newWatchlist = watchlist.filter(s => s !== stock.symbol);
    setWatchlist(newWatchlist);
    localStorage.setItem("watchlist", JSON.stringify(newWatchlist));
    
    // Remove from displayed stocks
    setStocks(stocks.filter(s => s.symbol !== stock.symbol));
  };

  // Calculate portfolio value and changes
  const totalValue = stocks.reduce((sum, stock) => sum + stock.price, 0);
  const totalChange = stocks.reduce((sum, stock) => sum + stock.change, 0);
  const totalChangePercent = totalValue > 0 ? (totalChange / (totalValue - totalChange)) * 100 : 0;

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-indigo-600 mx-auto mb-4"></div>
          <p className="text-gray-600">Loading your watchlist...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 py-8">
      <div className="container mx-auto px-4">
        <h1 className="text-3xl font-bold text-gray-800 mb-6">My Watchlist</h1>

        {watchlist.length > 0 ? (
          <>
            {/* Portfolio Summary */}
            <div className="bg-white rounded-lg shadow-md p-6 mb-6">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div>
                  <p className="text-sm text-gray-600 mb-1">Stocks in Watchlist</p>
                  <p className="text-2xl font-bold text-gray-800">{watchlist.length}</p>
                </div>
                <div>
                  <p className="text-sm text-gray-600 mb-1">Total Value</p>
                  <p className="text-2xl font-bold text-gray-800">₹{totalValue.toLocaleString('en-IN', { maximumFractionDigits: 2 })}</p>
                </div>
                <div>
                  <p className="text-sm text-gray-600 mb-1">Today's Change</p>
                  <div className={`text-2xl font-bold ${totalChange >= 0 ? "text-green-600" : "text-red-600"}`}>
                    {totalChange >= 0 ? "+" : ""}₹{totalChange.toFixed(2)}
                    <span className="text-sm ml-2">
                      ({totalChange >= 0 ? "+" : ""}{totalChangePercent.toFixed(2)}%)
                    </span>
                  </div>
                </div>
              </div>
            </div>

            {/* Watchlist Grid */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
              {stocks.map(stock => (
                <StockCard
                  key={stock.symbol}
                  stock={stock}
                  onToggleWatchlist={toggleWatchlist}
                  isInWatchlist={true}
                />
              ))}
            </div>
          </>
        ) : (
          <div className="text-center py-16">
            <div className="mb-6">
              <svg className="w-24 h-24 mx-auto text-gray-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M11.049 2.927c.3-.921 1.603-.921 1.902 0l1.519 4.674a1 1 0 00.95.69h4.915c.969 0 1.371 1.24.588 1.81l-3.976 2.888a1 1 0 00-.363 1.118l1.518 4.674c.3.922-.755 1.688-1.538 1.118l-3.976-2.888a1 1 0 00-1.176 0l-3.976 2.888c-.783.57-1.838-.197-1.538-1.118l1.518-4.674a1 1 0 00-.363-1.118l-3.976-2.888c-.784-.57-.38-1.81.588-1.81h4.914a1 1 0 00.951-.69l1.519-4.674z" />
              </svg>
            </div>
            <h2 className="text-2xl font-bold text-gray-800 mb-4">Your watchlist is empty</h2>
            <p className="text-gray-600 mb-6 max-w-md mx-auto">
              Start tracking your favorite stocks by adding them to your watchlist. 
              You'll get real-time updates on price changes.
            </p>
            <Link
              to="/markets"
              className="inline-block bg-indigo-600 text-white px-8 py-3 rounded-lg font-semibold hover:bg-indigo-700 transition-colors duration-200"
            >
              Explore Markets
            </Link>
          </div>
        )}
      </div>
    </div>
  );
}
